from pptx import Presentation
from pptx.util import Inches, Pt
from pptx.dml.color import RGBColor
import os
import json

output_dir = os.path.join('document_output', 'ppt_output')
os.makedirs(output_dir, exist_ok=True)
filepath = os.path.join(output_dir, f'{filename}.pptx')

formatting = None
if 'formatting' in dir() and formatting is not None:
    if isinstance(formatting, str):
        try:
            formatting = json.loads(formatting)
        except:
            formatting = None

if formatting and isinstance(formatting, dict):
    from agent.ppt_formatter import create_ppt_presentation
    result = create_ppt_presentation(filename, content=content, formatting=formatting, output_dir=output_dir)
else:
    prs = Presentation()
    prs.slide_width = Inches(13.333)
    prs.slide_height = Inches(7.5)

    slides_data = []
    current_slide = None
    for line in [l.strip() for l in content.replace(chr(13), '').split(chr(10)) if l.strip()]:
        if line.startswith('# '):
            if current_slide is not None:
                slides_data.append(current_slide)
            current_slide = {'title': line[2:].strip(), 'content': []}
        elif current_slide is not None:
            current_slide['content'].append(line)
    if current_slide is not None:
        slides_data.append(current_slide)

    if not slides_data:
        slides_data = [{'title': filename, 'content': [p.strip() for p in content.replace(chr(13), '').split(chr(10)) if p.strip()]}]

    for slide_data in slides_data:
        slide_layout = prs.slide_layouts[1]
        slide = prs.slides.add_slide(slide_layout)
        if slide.shapes.title:
            slide.shapes.title.text = slide_data['title']
        if slide_data['content'] and len(slide.placeholders) > 1:
            body = slide.placeholders[1]
            tf = body.text_frame
            tf.clear()
            for i, line in enumerate(slide_data['content']):
                if i == 0:
                    tf.paragraphs[0].text = line
                    tf.paragraphs[0].font.size = Pt(18)
                else:
                    p = tf.add_paragraph()
                    p.text = line
                    p.font.size = Pt(18)

    prs.save(filepath)
    result = f'PPT演示文稿已成功保存至: {filepath}'
